// Process ALL items (not just first one)
const allItems = $input.all();
const results = [];

const VALID_CATEGORIES = [
  'Food & Dining', 'Groceries', 'Gas & Fuel', 'Office Supplies',
  'Travel & Lodging', 'Utilities', 'Medical & Health', 'Entertainment',
  'Shopping', 'Transportation', 'Subscriptions', 'Home & Garden',
  'Auto & Maintenance', 'Personal Care', 'Education', 'Other'
];

const FIELD_MAP = {
  'document_type': null,
  'date': 'Date',
  'vendor': 'Vendor',
  'category': 'Category',
  'total': 'Total',
  'subtotal': 'Subtotal',
  'tax': 'Tax',
  'tip': 'Tip',
  'payment_method': 'Payment Method',
  'description': 'Description',
  'items': 'Items',
  'address': 'Address',
  'receipt_number': 'Receipt #',
  'invoice_number': 'Invoice #',
  'due_date': 'Due Date',
  'billed_to': 'Billed To'
};

for (const item of allItems) {
  try {
    let raw = item.json.output ?? '';
    if (typeof raw !== 'string') raw = JSON.stringify(raw);
    raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();
    const jsonMatch = raw.match(/\{[\s\S]*\}/);
    if (!jsonMatch) {
      console.log('No JSON found in AI response, skipping item');
      continue;
    }
    const data = JSON.parse(jsonMatch[0]);

    if (!data.category || !VALID_CATEGORIES.includes(data.category)) {
      const cat = (data.category || '').toLowerCase();
      const match = VALID_CATEGORIES.find(c => cat.includes(c.split(' ')[0].toLowerCase()));
      data.category = match || 'Other';
    }

    if (Array.isArray(data.items)) {
      data.items = data.items.map(item => {
        if (typeof item === 'string') return item;
        const name = item.name || item.description || item.item || 'Item';
        const price = item.total_price || item.unit_price || item.price || item.amount;
        return price != null ? `${name} $${price}` : name;
      }).join(' \u00b7 ');
    } else if (data.line_items) {
      const li = Array.isArray(data.line_items) ? data.line_items : [];
      data.items = li.map(item => {
        if (typeof item === 'string') return item;
        const name = item.name || item.description || item.item || 'Item';
        const price = item.total_price || item.unit_price || item.price || item.amount;
        return price != null ? `${name} $${price}` : name;
      }).join(' \u00b7 ');
      delete data.line_items;
    }

    const row = {};
    row.document_type = data.document_type || 'receipt';
    for (const [field, header] of Object.entries(FIELD_MAP)) {
      if (!header) continue;
      if (data[field] !== undefined && data[field] !== null && data[field] !== '') {
        row[header] = data[field];
      }
    }
    results.push({ json: row });
  } catch (e) {
    console.log('Error processing item: ' + e.message);
  }
}

return results;

const { document_type, ...rest } = $input.item.json;
const data = { ...rest, 'Payment Status': 'Unpaid' };
return [{ json: data }];

// The Drive API returns {files: [...]}
// Split into individual items, filtering out Google Workspace files
// (Sheets, Docs, etc.) that can't be downloaded as receipts
const files = $json.files || [];
const downloadable = files.filter(f => !f.mimeType.startsWith('application/vnd.google-apps.'));
return downloadable.map(f => ({json: f}));
